20	var statusCmd = &cobra.Command{
21		Use:   "status",
22		Short: "Show version and status information",
23		Long: `Show comprehensive version and status information for your DDX project.
24	
25	This command displays:
26	- Current DDX version and commit hash
27	- Last update timestamp
28	- Local modifications to DDX resources
29	- Available upstream updates
30	- Change history and differences
31	
32	Examples:
33	  ddx status                          # Show basic status
34	  ddx status --verbose                # Show detailed information
35	  ddx status --check-upstream         # Check for updates
36	  ddx status --changes                # List changed files
37	  ddx status --diff                   # Show differences
38	  ddx status --export manifest.yml    # Export version manifest`,
39		RunE: runStatus,
40	}
