47	func (f *CommandFactory) runStatus(cmd *cobra.Command, args []string) error {
48		// Get flag values
49		checkUpstream, _ := cmd.Flags().GetBool("check-upstream")
50		showChanges, _ := cmd.Flags().GetBool("changes")
51		showDiff, _ := cmd.Flags().GetBool("diff")
52		exportPath, _ := cmd.Flags().GetString("export")
53	
54		// Call pure business logic
55		status, err := checkStatus(f.WorkingDir, checkUpstream, showChanges, showDiff)
56		if err != nil {
57			return err
58		}
59	
60		// Handle export if requested
61		if exportPath != "" {
62			return exportStatusManifest(cmd, status, exportPath)
63		}
64	
65		// Display results
66		displayStatus(cmd, status, showChanges, showDiff)
67		return nil
68	}
