110	// checkStatus is the pure business logic function
111	func checkStatus(workingDir string, checkUpstream, showChanges, showDiff bool) (*StatusInfo, error) {
112		start := time.Now()
113	
114		// Verify we're in a DDx project
115		if !isDDXProjectInDir(workingDir) {
116			return nil, fmt.Errorf("not a DDX project - run 'ddx init' first")
117		}
118	
119		status := &StatusInfo{
120			Performance: PerformanceInfo{
121				CollectionTime: time.Since(start),
122			},
123		}
124	
125		// Get version information
126		version, hash, err := getVersionInfoFromDir(workingDir)
127		if err != nil {
128			return nil, err
129		}
130		status.Version = version
131		status.CommitHash = hash
132	
133		// Get last updated time
134		lastUpdated, err := getLastUpdatedTimeFromDir(workingDir)
135		if err != nil {
136			return nil, err
137		}
138		status.LastUpdated = lastUpdated
139	
140		// Check for local modifications
141		modifications, err := getLocalModificationsFromDir(workingDir)
142		if err != nil {
143			return nil, err
144		}
145		status.Modifications = modifications
146	
147		// Check upstream updates if requested
148		if checkUpstream {
149			upstream, err := checkUpstreamUpdatesFromDir(workingDir)
150			if err != nil {
151				return nil, err
152			}
153			status.UpstreamInfo = upstream
154		}
155	
156		// Collect resource information
157		resources, err := getStatusResourcesFromDir(workingDir)
158		if err != nil {
159			return nil, err
160		}
161		status.Resources = resources
162		status.Usage = collectStatusUsage(workingDir)
163	
164		status.Performance.CollectionTime = time.Since(start)
165		return status, nil
166	}
