168	func collectStatusUsage(workingDir string) []usageRow {
169		since, err := parseSince("30d")
170		if err != nil {
171			return nil
172		}
173	
174		logDir := agent.SessionLogDirForWorkDir(workingDir)
175		rows, err := aggregateUsageFromRoutingMetrics(logDir, "", since)
176		if err != nil {
177			return nil
178		}
179		if len(rows) == 0 {
180			rows, err = aggregateUsageFromSessionIndex(logDir, "", since, nil)
181		}
182		if err != nil || len(rows) == 0 {
183			return nil
184		}
185	
186		return enrichUsageRowsWithRoutingSignals(workingDir, rows)
187	}
