189	func getVersionInfoFromDir(workingDir string) (version, hash string, err error) {
190		// Try to get from .ddx.yml first
191		configPath := ".ddx.yml"
192		if workingDir != "" {
193			configPath = filepath.Join(workingDir, ".ddx.yml")
194		}
195	
196		// Create a temporary viper instance for this specific config
197		v := viper.New()
198		v.SetConfigFile(configPath)
199		if err := v.ReadInConfig(); err == nil {
200			version = v.GetString("version")
201		}
202	
203		if version == "" {
204			version = "v0.0.1" // Default if not set
205		}
206	
207		// Get git commit hash from .ddx directory
208		ddxDir := ".ddx"
209		if workingDir != "" {
210			ddxDir = filepath.Join(workingDir, ".ddx")
211		}
212	
213		if _, err := os.Stat(ddxDir); os.IsNotExist(err) {
214			return version, "unknown", nil
215		}
216	
217		cmd := gitpkg.Command(context.Background(), ddxDir, "rev-parse", "--short", "HEAD")
218		output, err := cmd.Output()
219		if err != nil {
220			hash = "unknown"
221		} else {
222			hash = strings.TrimSpace(string(output))
223		}
224	
225		return version, hash, nil
226	}
