228	func getLastUpdatedTimeFromDir(workingDir string) (time.Time, error) {
229		configPath := ".ddx.yml"
230		if workingDir != "" {
231			configPath = filepath.Join(workingDir, ".ddx.yml")
232		}
233	
234		// Create a temporary viper instance for this specific config
235		v := viper.New()
236		v.SetConfigFile(configPath)
237		if err := v.ReadInConfig(); err == nil {
238			lastUpdatedStr := v.GetString("last_updated")
239			if lastUpdatedStr != "" {
240				if t, err := time.Parse(time.RFC3339, lastUpdatedStr); err == nil {
241					return t, nil
242				}
243			}
244		}
245	
246		// Fallback to .ddx.yml modification time
247		if info, err := os.Stat(configPath); err == nil {
248			return info.ModTime(), nil
249		}
250	
251		return time.Now(), nil
252	}
