254	func getLocalModificationsFromDir(workingDir string) ([]ModifiedFile, error) {
255		var modifications []ModifiedFile
256	
257		ddxDir := ".ddx"
258		if workingDir != "" {
259			ddxDir = filepath.Join(workingDir, ".ddx")
260		}
261	
262		if _, err := os.Stat(ddxDir); os.IsNotExist(err) {
263			return modifications, nil
264		}
265	
266		// Use git status to detect modifications
267		cmd := gitpkg.Command(context.Background(), ddxDir, "status", "--porcelain")
268		output, err := cmd.Output()
269		if err != nil {
270			// If git not available, scan for recent modifications
271			return scanForModificationsInDir(ddxDir)
272		}
273	
274		lines := strings.Split(strings.TrimSpace(string(output)), "\n")
275		for _, line := range lines {
276			if line == "" {
277				continue
278			}
279	
280			status := line[:2]
281			path := strings.TrimSpace(line[2:])
282	
283			var modType string
284			switch {
285			case strings.Contains(status, "M"):
286				modType = "modified"
287			case strings.Contains(status, "A"):
288				modType = "added"
289			case strings.Contains(status, "D"):
290				modType = "deleted"
291			default:
292				modType = "modified"
293			}
294	
295			fullPath := filepath.Join(ddxDir, path)
296			var modTime time.Time
297			if info, err := os.Stat(fullPath); err == nil {
298				modTime = info.ModTime()
299			}
300	
301			modifications = append(modifications, ModifiedFile{
302				Path:         path,
303				Type:         modType,
304				LastModified: modTime,
305			})
306		}
307	
308		return modifications, nil
309	}
