311	func scanForModificationsInDir(ddxDir string) ([]ModifiedFile, error) {
312		var modifications []ModifiedFile
313	
314		err := filepath.Walk(ddxDir, func(path string, info os.FileInfo, err error) error {
315			if err != nil {
316				return nil // Skip errors
317			}
318	
319			if info.IsDir() {
320				return nil
321			}
322	
323			// Check if file was modified recently (within last hour)
324			if time.Since(info.ModTime()) < time.Hour {
325				relPath, _ := filepath.Rel(ddxDir, path)
326				modifications = append(modifications, ModifiedFile{
327					Path:         relPath,
328					Type:         "modified",
329					LastModified: info.ModTime(),
330				})
331			}
332	
333			return nil
334		})
335	
336		return modifications, err
337	}
