357	func getStatusResourcesFromDir(workingDir string) ([]StatusResourceInfo, error) {
358		var resources []StatusResourceInfo
359	
360		ddxDir := ".ddx"
361		if workingDir != "" {
362			ddxDir = filepath.Join(workingDir, ".ddx")
363		}
364	
365		if _, err := os.Stat(ddxDir); os.IsNotExist(err) {
366			return resources, nil
367		}
368	
369		resourceTypes := map[string]string{
370			"templates": "template",
371			"patterns":  "pattern",
372			"prompts":   "prompt",
373			"configs":   "config",
374			"scripts":   "script",
375		}
376	
377		for dir, resourceType := range resourceTypes {
378			resourceDir := filepath.Join(ddxDir, dir)
379			if _, err := os.Stat(resourceDir); os.IsNotExist(err) {
380				continue
381			}
382	
383			err := filepath.Walk(resourceDir, func(path string, info os.FileInfo, err error) error {
384				if err != nil || info.IsDir() {
385					return nil
386				}
387	
388				relPath, _ := filepath.Rel(ddxDir, path)
389				resources = append(resources, StatusResourceInfo{
390					Path:        relPath,
391					Type:        resourceType,
392					LastUpdated: info.ModTime(),
393				})
394	
395				return nil
396			})
397	
398			if err != nil {
399				return nil, err
400			}
401		}
402	
403		// Sort by type and path for consistent output
404		sort.Slice(resources, func(i, j int) bool {
405			if resources[i].Type != resources[j].Type {
406				return resources[i].Type < resources[j].Type
407			}
408			return resources[i].Path < resources[j].Path
409		})
410	
411		return resources, nil
412	}
