414	func displayStatus(cmd *cobra.Command, status *StatusInfo, showChanges, showDiff bool) {
415		_, _ = fmt.Fprintln(cmd.OutOrStdout(), "DDX Status Report")
416		_, _ = fmt.Fprintln(cmd.OutOrStdout(), "================")
417		_, _ = fmt.Fprintf(cmd.OutOrStdout(), "Current Version: %s (%s)\n", status.Version, status.CommitHash)
418		_, _ = fmt.Fprintf(cmd.OutOrStdout(), "Last Updated: %s\n", status.LastUpdated.Format("2006-01-02 15:04:05"))
419	
420		if status.UpstreamInfo != nil && status.UpstreamInfo.Available {
421			_, _ = fmt.Fprintf(cmd.OutOrStdout(), "Upstream: %s available\n", status.UpstreamInfo.LatestVersion)
422		}
423		_, _ = fmt.Fprintln(cmd.OutOrStdout())
424	
425		// Show modifications
426		if len(status.Modifications) > 0 {
427			_, _ = fmt.Fprintln(cmd.OutOrStdout(), "Modified Resources:")
428			for _, mod := range status.Modifications {
429				_, _ = fmt.Fprintf(cmd.OutOrStdout(), "- %s (%s)\n", mod.Path, mod.Type)
430			}
431			_, _ = fmt.Fprintln(cmd.OutOrStdout())
432		}
433	
434		// Show upstream updates
435		if status.UpstreamInfo != nil && len(status.UpstreamInfo.Updates) > 0 {
436			_, _ = fmt.Fprintln(cmd.OutOrStdout(), "Updates Available:")
437			for _, update := range status.UpstreamInfo.Updates {
438				_, _ = fmt.Fprintf(cmd.OutOrStdout(), "- %s (%s)\n", update.Path, update.Type)
439			}
440			_, _ = fmt.Fprintln(cmd.OutOrStdout())
441		}
442	
443		if len(status.Usage) > 0 {
444			_, _ = fmt.Fprintln(cmd.OutOrStdout(), "Agent Usage (30d):")
445			_, _ = fmt.Fprintf(cmd.OutOrStdout(), "%-12s  %8s  %13s  %14s  %10s  %-15s  %-8s  %10s  %-18s  %-10s\n",
446				"HARNESS", "SESSIONS", "INPUT TOKENS", "OUTPUT TOKENS", "EST. COST", "COST BASIS", "QUOTA", "USED", "SOURCE", "FRESHNESS")
447			for _, row := range status.Usage {
448				source := row.SignalProvider
449				if row.SignalKind != "" {
450					if source != "" {
451						source += "/"
452					}
453					source += row.SignalKind
454				}
455				_, _ = fmt.Fprintf(cmd.OutOrStdout(), "%-12s  %8d  %13s  %14s  %10s  %-15s  %-8s  %10s  %-18s  %-10s\n",
456					row.Harness,
457					row.Sessions,
458					formatComma(row.InputTokens),
459					formatComma(row.OutputTokens),
460					fmt.Sprintf("$%.2f", row.CostUSD),
461					row.CostBasis,
462					row.QuotaState,
463					formatUsageQuotaUsed(row),
464					source,
465					row.SignalFreshness,
466				)
467			}
468			_, _ = fmt.Fprintln(cmd.OutOrStdout())
469		}
470	
471		// Show verbose information
472		if viper.GetBool("verbose") {
473			_, _ = fmt.Fprintf(cmd.OutOrStdout(), "Performance: Collection took %v\n", status.Performance.CollectionTime)
474	
475			if len(status.Resources) > 0 {
476				_, _ = fmt.Fprintln(cmd.OutOrStdout(), "\nResource Details:")
477				for _, resource := range status.Resources {
478					_, _ = fmt.Fprintf(cmd.OutOrStdout(), "- %s [%s] - %s\n",
479						resource.Path,
480						resource.Type,
481						resource.LastUpdated.Format("2006-01-02 15:04:05"))
482				}
483			}
484		}
485	
486		// Show changes if requested
487		if showChanges && len(status.Modifications) > 0 {
488			_, _ = fmt.Fprintln(cmd.OutOrStdout(), "\nChanged Files:")
489			for _, mod := range status.Modifications {
490				_, _ = fmt.Fprintf(cmd.OutOrStdout(), "- %s (%s) - %s\n",
491					mod.Path,
492					mod.Type,
493					mod.LastModified.Format("2006-01-02 15:04:05"))
494			}
495		}
496	
497		// Show differences if requested
498		if showDiff {
499			_, _ = fmt.Fprintln(cmd.OutOrStdout(), "\nDifferences:")
500			// This would show actual git diff output
501			_, _ = fmt.Fprintln(cmd.OutOrStdout(), "(diff functionality would show detailed changes here)")
502		}
503	}
