505	func formatUsageQuotaUsed(row usageRow) string {
506		if row.QuotaState == "" && row.SignalProvider == "" && row.SignalKind == "" {
507			return ""
508		}
509		return fmt.Sprintf("%d%%", row.NativeQuotaUsedPercent)
510	}
