512	func exportStatusManifest(cmd *cobra.Command, status *StatusInfo, path string) error {
513		var data []byte
514		var err error
515	
516		switch {
517		case strings.HasSuffix(path, ".json"):
518			data, err = json.MarshalIndent(status, "", "  ")
519		case strings.HasSuffix(path, ".yml") || strings.HasSuffix(path, ".yaml"):
520			data, err = yaml.Marshal(status)
521		default:
522			// Default to YAML
523			data, err = yaml.Marshal(status)
524		}
525	
526		if err != nil {
527			return fmt.Errorf("failed to marshal status data: %w", err)
528		}
529	
530		err = os.WriteFile(path, data, 0644)
531		if err != nil {
532			return fmt.Errorf("failed to write manifest file: %w", err)
533		}
534	
535		_, _ = fmt.Fprintf(cmd.OutOrStdout(), "Status manifest exported to: %s\n", path)
536		return nil
537	}
