46	// recentRoutingDecision is a merged view of a single routing decision sourced from
47	// either the RoutingMetricsStore or a kind:routing bead evidence event.
48	//
49	// Both RoutingMetricsStore and kind:routing bead events are intentionally kept:
50	//   - RoutingMetricsStore (.ddx/agent-logs/routing-outcomes.jsonl) records
51	//     harness-level analytics (latency, success rate) for every agent run.
52	//   - kind:routing bead evidence records execution provenance per bead: which
53	//     provider/model was selected and why, tied to a specific bead ID.
54	type recentRoutingDecision struct {
55		ObservedAt   time.Time
56		Source       string // "bead-evidence" or "metrics-store"
57		BeadID       string // populated for bead-evidence entries
58		Harness      string // populated for metrics-store entries
59		Provider     string // resolved_provider (bead-evidence) or CanonicalTarget (metrics-store)
60		Model        string
61		RouteReason  string // populated for bead-evidence entries
62		Success      bool   // populated for metrics-store entries
63		SuccessKnown bool   // false for bead-evidence entries (success not recorded)
64		LatencyMS    int    // populated for metrics-store entries
65	}
