444							d.Source,
445							truncateRouteStr(d.Provider, 24),
446							truncateRouteStr(d.Model, 20),
447							ok,
448							d.BeadID,
449						)
450					}
451				}
452	
453				// --- Section 3: Active Health Cooldowns ---
454				fmt.Fprintln(out)
455				fmt.Fprintf(out, "Active Health Cooldowns\n")
