288	// CapabilitiesViaService returns HarnessCapabilities for the named harness by
289	// querying the service's ListHarnesses and (best-effort) the harness registry.
290	// It is the production replacement for Runner.Capabilities.
291	func CapabilitiesViaService(ctx context.Context, workDir, harnessName string) (*HarnessCapabilities, error) {
292		if ctx == nil {
293			ctx = context.Background()
294		}
295		svc, err := NewServiceFromWorkDir(workDir)
296		if err != nil {
297			return nil, fmt.Errorf("agent: build service: %w", err)
298		}
299		infos, err := svc.ListHarnesses(ctx)
300		if err != nil {
301			return nil, fmt.Errorf("agent: list harnesses: %w", err)
302		}
303		var info *agentlib.HarnessInfo
304		for i := range infos {
305			if infos[i].Name == harnessName {
306				info = &infos[i]
307				break
308			}
309		}
310		if info == nil {
311			return nil, fmt.Errorf("agent: unknown harness: %s", harnessName)
312		}
313	
314		// Pull binary and reasoning-level metadata from the local registry — the
315		// service does not expose these directly today.
316		registry := newHarnessRegistry()
317		harness, _ := registry.Get(harnessName)
318	
319		caps := &HarnessCapabilities{
320			Harness:             info.Name,
321			Available:           info.Available,
322			Binary:              harness.Binary,
323			Path:                info.Path,
324			Surface:             harness.Surface,
325			CostClass:           info.CostClass,
326			IsLocal:             info.IsLocal,
327			ExactPinSupport:     info.ExactPinSupport,
328			SupportsEffort:      len(info.SupportedReasoning) > 0 || harness.EffortFlag != "",
329			SupportsPermissions: len(info.SupportedPermissions) > 0 || len(harness.PermissionArgs) > 0,
330		}
331		if len(info.SupportedReasoning) > 0 {
332			caps.ReasoningLevels = append([]string{}, info.SupportedReasoning...)
333		} else if len(harness.ReasoningLevels) > 0 {
334			caps.ReasoningLevels = append([]string{}, harness.ReasoningLevels...)
335		}
336	
337		if harness.DefaultModel != "" {
338			caps.Model = harness.DefaultModel
339			caps.Models = []string{harness.DefaultModel}
340		}
341	
342		return caps, nil
343	}
