345	// TestProviderConnectivityViaService runs a HealthCheck against the named
346	// harness and translates the result into a ProviderStatus. It is the
347	// production replacement for Runner.TestProviderConnectivity.
348	func TestProviderConnectivityViaService(ctx context.Context, workDir, harnessName string, timeout time.Duration) ProviderStatus {
349		status := ProviderStatus{Reachable: false}
350		if ctx == nil {
351			ctx = context.Background()
352		}
353		if harnessName == "virtual" || harnessName == "agent" {
354			status.Reachable = true
355			status.CreditsOK = true
356			return status
357		}
358		svc, err := NewServiceFromWorkDir(workDir)
359		if err != nil {
360			status.Error = err.Error()
361			return status
362		}
363		if timeout > 0 {
364			var cancel context.CancelFunc
365			ctx, cancel = context.WithTimeout(ctx, timeout)
366			defer cancel()
367		}
368		if err := svc.HealthCheck(ctx, agentlib.HealthTarget{Type: "harness", Name: harnessName}); err != nil {
369			errStr := strings.ToLower(err.Error())
370			status.Error = err.Error()
371			if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
372				strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
373				status.CreditsOK = false
374			}
375			return status
376		}
377		status.Reachable = true
378		status.CreditsOK = true
379		return status
380	}
