37	// DefaultModelCatalogPath returns the default path for the model catalog YAML.
38	func DefaultModelCatalogPath() string {
39		home, err := os.UserHomeDir()
40		if err != nil || home == "" {
41			return ""
42		}
43		return filepath.Join(home, ".ddx", "model-catalog.yaml")
44	}
