35	// Catalog holds the shared DDx model catalog used for harness routing.
36	// It maps logical refs to harness-surface-specific concrete model strings.
37	// This is the authoritative source for aliases, profiles, canonical targets,
38	// and deprecation metadata across harness surfaces.
39	type Catalog struct {
40		entries         map[string]CatalogEntry
41		deprecatedPins  map[string]DeprecatedPin // keyed by Pin
42		blockedModelIDs map[string]bool          // concrete model IDs that routing must never select
43	}
44	
45	// catalog returns the catalog to use for runtime model metadata checks.
46	// Defaults to BuiltinCatalog.
47	func (r *Runner) catalog() *Catalog {
48		if r.Catalog != nil {
49			return r.Catalog
50		}
51		return BuiltinCatalog
52	}
53	
54	// NewCatalog creates a Catalog from a slice of entries.
55	func NewCatalog(entries []CatalogEntry) *Catalog {
56		c := &Catalog{entries: make(map[string]CatalogEntry, len(entries))}
57		for _, e := range entries {
58			c.entries[e.Ref] = e
59		}
60		return c
61	}
62	
63	// NewCatalogWithPins creates a Catalog from entries and deprecated pin records.
64	func NewCatalogWithPins(entries []CatalogEntry, pins []DeprecatedPin) *Catalog {
65		c := NewCatalog(entries)
66		c.deprecatedPins = make(map[string]DeprecatedPin, len(pins))
67		for _, p := range pins {
68			c.deprecatedPins[p.Pin] = p
69		}
70		return c
71	}
72	
73	// Clone returns an independent copy of the catalog.
74	func (c *Catalog) Clone() *Catalog {
75		if c == nil {
76			return NewCatalog(nil)
77		}
78		clone := &Catalog{
79			entries:         make(map[string]CatalogEntry, len(c.entries)),
80			deprecatedPins:  make(map[string]DeprecatedPin, len(c.deprecatedPins)),
81			blockedModelIDs: make(map[string]bool, len(c.blockedModelIDs)),
82		}
83		for ref, entry := range c.entries {
84			surfaces := make(map[string]string, len(entry.Surfaces))
85			for surface, model := range entry.Surfaces {
86				surfaces[surface] = model
87			}
88			entry.Surfaces = surfaces
89			clone.entries[ref] = entry
90		}
91		for pin, entry := range c.deprecatedPins {
92			clone.deprecatedPins[pin] = entry
93		}
94		for id, blocked := range c.blockedModelIDs {
95			clone.blockedModelIDs[id] = blocked
96		}
97		return clone
98	}
99	
100	// AddOrReplace inserts or replaces a catalog entry by Ref.
101	func (c *Catalog) AddOrReplace(entry CatalogEntry) {
102		if c.entries == nil {
103			c.entries = make(map[string]CatalogEntry)
104		}
105		c.entries[entry.Ref] = entry
106	}
107	
108	// AddBlockedModelID marks a concrete model ID as blocked.
109	// Resolve() returns ok=false for any model that resolves to a blocked ID.
110	func (c *Catalog) AddBlockedModelID(id string) {
111		if c.blockedModelIDs == nil {
112			c.blockedModelIDs = make(map[string]bool)
113		}
114		c.blockedModelIDs[id] = true
115	}
116	
117	// IsBlockedModelID reports whether a concrete model ID is blocked.
118	func (c *Catalog) IsBlockedModelID(id string) bool {
119		return c.blockedModelIDs[id]
120	}
121	
122	// CheckDeprecatedPin returns the DeprecatedPin entry for an explicit model
123	// string, or ok=false if the pin is not deprecated.
124	// If surface is non-empty and the pin entry has a Surface set, the match is
125	// narrowed to that surface only.
126	func (c *Catalog) CheckDeprecatedPin(pin, surface string) (DeprecatedPin, bool) {
127		if c.deprecatedPins == nil {
128			return DeprecatedPin{}, false
129		}
130		dp, ok := c.deprecatedPins[pin]
131		if !ok {
132			return DeprecatedPin{}, false
133		}
134		if dp.Surface != "" && surface != "" && dp.Surface != surface {
135			return DeprecatedPin{}, false
136		}
137		return dp, true
138	}
139	
140	// Resolve returns the concrete model string for a ref on the given surface.
141	// Returns ("", false) if the ref is unknown, not mapped to this surface,
142	// the entry is blocked, or the resolved concrete model is blocked.
143	func (c *Catalog) Resolve(ref, surface string) (string, bool) {
144		e, ok := c.entries[ref]
145		if !ok {
146			return "", false
147		}
148		if e.Blocked {
149			return "", false
150		}

