183	func (f *CommandFactory) newAgentRouteStatusCommand() *cobra.Command {
184		cmd := &cobra.Command{
185			Use:   "route-status",
186			Short: "Show routing table, recent decisions, and active health cooldowns",
187			Long: `Shows the current provider routing state, recent routing decisions, and
188	any health cooldowns currently in effect.
189	
190	Examples:
191	  ddx agent route-status
192	  ddx agent route-status --model qwen3.5-27b
193	  ddx agent route-status --json`,
194			Args: cobra.NoArgs,
195			RunE: func(cmd *cobra.Command, args []string) error {
196				model, _ := cmd.Flags().GetString("model")
197				asJSON, _ := cmd.Flags().GetBool("json")
198	
199				svc, err := agent.NewServiceFromWorkDir(f.WorkingDir)
200				if err != nil {
201					return fmt.Errorf("loading agent config: %w", err)
202				}
203	
204				ctx := context.Background()
205				report, err := svc.RouteStatus(ctx)
206				if err != nil {
207					return fmt.Errorf("getting route status: %w", err)
208				}
209	
210				// Filter by --model flag if specified.
211				if model != "" {
212					found := false
213					for _, r := range report.Routes {
214						if r.Model == model {
215							found = true
216							break
217						}
218					}
219					if !found {
220						return fmt.Errorf("no route configured for model key %q — check .agent/config.yaml", model)
221					}
222					filtered := report.Routes[:0]
223					for _, r := range report.Routes {
224						if r.Model == model {
225							filtered = append(filtered, r)
226						}
227					}
228					report.Routes = filtered
229				}
230	
231				if len(report.Routes) == 0 {
232					if !asJSON {
233						fmt.Fprintln(cmd.OutOrStdout(), "No model routes configured in .agent/config.yaml.")
234						fmt.Fprintln(cmd.OutOrStdout(), "Use --model <route-key> or configure model_routes in .agent/config.yaml.")
235					} else {
236						enc := json.NewEncoder(cmd.OutOrStdout())
237						enc.SetIndent("", "  ")
238						return enc.Encode(routeStatusJSON{})
239					}
240					return nil
241				}
242	
243				// Load recent routing decisions from two complementary sources:
244				//
245				//  1. RoutingMetricsStore — harness-level analytics (latency, success
246				//     rate) for every agent run, stored in routing-outcomes.jsonl.
247				//  2. kind:routing bead events — execution provenance per bead (which
248				//     provider/model was selected and why), tied to a specific bead ID.
249				var recentDecisions []recentRoutingDecision
250	
251				if logDir := agent.SessionLogDirForWorkDir(f.WorkingDir); logDir != "" {
252					store := agent.NewRoutingMetricsStore(logDir)
253					outcomes, _ := store.ReadOutcomes()
254					for _, o := range outcomes {
255						recentDecisions = append(recentDecisions, recentRoutingDecision{
256							ObservedAt:   o.ObservedAt,
257							Source:       "metrics-store",
258							Harness:      o.Harness,
259							Provider:     o.CanonicalTarget,
260							Model:        o.Model,
261							Success:      o.Success,
262							SuccessKnown: true,
263							LatencyMS:    o.LatencyMS,
264						})
265					}
266				}
267	
268				// Merge kind:routing bead evidence entries.
269				recentDecisions = append(recentDecisions, beadRoutingDecisionsFromStore(f.WorkingDir)...)
270	
271				// Sort by time and take the last N.
272				sort.Slice(recentDecisions, func(i, j int) bool {
273					return recentDecisions[i].ObservedAt.Before(recentDecisions[j].ObservedAt)
274				})
275				const maxRecent = 10
276				if len(recentDecisions) > maxRecent {
277					recentDecisions = recentDecisions[len(recentDecisions)-maxRecent:]
278				}
279	
280				// Collect active cooldowns across all routes from the report.
281				type cooldownEntry struct {
282					route         string
283					provider      string
284					failedAt      time.Time
285					cooldownUntil time.Time
286				}
287				var activeCooldowns []cooldownEntry
288				seenCooldownKeys := make(map[string]struct{})
289				for _, entry := range report.Routes {
290					for _, cand := range entry.Candidates {
291						if cand.Cooldown != nil && time.Now().Before(cand.Cooldown.Until) {
292							ck := entry.Model + "|" + cand.Provider
293							if _, seen := seenCooldownKeys[ck]; !seen {
294								seenCooldownKeys[ck] = struct{}{}
295								// FailedAt is not directly available; use Until minus a best-effort estimate.
296								// We record Until and leave FailedAt as zero for cooldowns from the service.
297								activeCooldowns = append(activeCooldowns, cooldownEntry{
298									route:         entry.Model,
299									provider:      cand.Provider,
300									cooldownUntil: cand.Cooldown.Until,
301								})
302							}
303						}
304					}
305				}
306				sort.Slice(activeCooldowns, func(i, j int) bool {
307					return activeCooldowns[i].route < activeCooldowns[j].route
308				})
309	
310				if asJSON {
311					payload := routeStatusJSON{}
312					for _, entry := range report.Routes {
313						rj := routeStatusRouteJSON{
314							RouteKey: entry.Model,
315							Strategy: entry.Strategy,
316						}
317						for _, cand := range entry.Candidates {
318							cj := routeStatusCandidateJSON{
319								Provider:      cand.Provider,
320								Model:         cand.Model,
321								Healthy:       cand.Healthy,
322								AvgDurationMs: cand.RecentLatencyMS,
323								Reliability:   cand.ProviderReliabilityRate,
324							}
325							if cand.Cooldown != nil && !cand.Cooldown.Until.IsZero() {
326								cj.InCooldown = true
327								cj.CooldownUntil = cand.Cooldown.Until.UTC().Format(time.RFC3339)
328								cj.Reason = fmt.Sprintf("cooldown until %s", cand.Cooldown.Until.Format(time.RFC3339))
329							}
330							rj.Candidates = append(rj.Candidates, cj)
331							if cand.Healthy && rj.SelectedProvider == "" {
332								rj.SelectedProvider = cand.Provider
333								rj.SelectedModel = cand.Model
334							}
335						}
336						payload.Routes = append(payload.Routes, rj)
337					}
338					for _, d := range recentDecisions {
339						jd := routeStatusDecisionJSON{
340							ObservedAt:  d.ObservedAt.UTC().Format(time.RFC3339),
341							Source:      d.Source,
342							BeadID:      d.BeadID,
343							Harness:     d.Harness,
344							Provider:    d.Provider,
345							Model:       d.Model,
346							RouteReason: d.RouteReason,
347						}
348						if d.Source == "metrics-store" {
349							jd.CanonicalTarget = d.Provider
350							jd.Success = d.Success
351							jd.LatencyMs = d.LatencyMS
352						}
353						payload.RecentDecisions = append(payload.RecentDecisions, jd)
354					}
355					for _, c := range activeCooldowns {
356						cd := routeStatusCooldownJSON{
357							Route:         c.route,
358							Provider:      c.provider,
359							CooldownUntil: c.cooldownUntil.UTC().Format(time.RFC3339),
360						}
361						if !c.failedAt.IsZero() {
362							cd.FailedAt = c.failedAt.UTC().Format(time.RFC3339)
363						}
364						payload.ActiveCooldowns = append(payload.ActiveCooldowns, cd)
365					}
366					enc := json.NewEncoder(cmd.OutOrStdout())
367					enc.SetIndent("", "  ")
368					return enc.Encode(payload)
369				}
370	
371				out := cmd.OutOrStdout()
372	
373				// --- Section 1: Route Table ---
374				for i, entry := range report.Routes {
375					if i > 0 {
376						fmt.Fprintln(out)
377					}
378	
379					selectedProvider := ""
380					selectedModel := ""
381					for _, cand := range entry.Candidates {
382						if cand.Healthy {
383							selectedProvider = cand.Provider
384							selectedModel = cand.Model
385							break
386						}
387					}
388	
389					strategy := entry.Strategy
390					if strategy == "" {
391						strategy = "first-available"
392					}
393	
394					fmt.Fprintf(out, "Route: %s\n", entry.Model)
395					fmt.Fprintf(out, "Strategy: %s\n", strategy)
396					if selectedProvider != "" {
397						fmt.Fprintf(out, "Selected: %s (%s)\n", selectedProvider, selectedModel)
398					} else {
399						fmt.Fprintf(out, "Selected: (none — all candidates down or in cooldown)\n")
400					}
401	
402					fmt.Fprintf(out, "%-12s %-32s %-10s %-10s %-10s %-12s %s\n",
403						"PROVIDER", "MODEL", "HEALTH", "SCORE", "RELIABILITY", "LATENCY_MS", "REASON")
404					for _, cand := range entry.Candidates {
405						health := "available"
406						reason := ""
407						if cand.Cooldown != nil && !cand.Cooldown.Until.IsZero() {
408							health = "cooldown"
409							reason = fmt.Sprintf("cooldown until %s", cand.Cooldown.Until.Format(time.RFC3339))
410						} else if !cand.Healthy {
411							health = "down"
412						}
413						fmt.Fprintf(out, "%-12s %-32s %-10s %-10.3f %-10.2f %-12.0f %s\n",
414							cand.Provider,
415							truncateRouteStr(cand.Model, 32),
416							health,
417							0.0, // Score not provided by RouteStatusReport
418							cand.ProviderReliabilityRate,
419							cand.RecentLatencyMS,
420							reason,
421						)
422					}
423				}
424	
425				// --- Section 2: Recent Routing Decisions ---
426				fmt.Fprintln(out)
427				fmt.Fprintf(out, "Recent Routing Decisions (last %d)\n", len(recentDecisions))
428				fmt.Fprintf(out, "%s\n", strings.Repeat("-", 90))
429				if len(recentDecisions) == 0 {
430					fmt.Fprintln(out, "  (no recorded decisions)")
431				} else {
432					fmt.Fprintf(out, "%-22s %-14s %-24s %-20s %-6s %s\n",
433						"OBSERVED_AT", "SOURCE", "PROVIDER", "MODEL", "OK", "BEAD")
434					for _, d := range recentDecisions {
435						ok := "-"
436						if d.SuccessKnown {
437							ok = "no"
438							if d.Success {
439								ok = "yes"
440							}
441						}
442						fmt.Fprintf(out, "%-22s %-14s %-24s %-20s %-6s %s\n",
443							d.ObservedAt.UTC().Format("2006-01-02T15:04:05Z"),
444							d.Source,
445							truncateRouteStr(d.Provider, 24),
446							truncateRouteStr(d.Model, 20),
447							ok,
448							d.BeadID,
449						)
450					}
451				}
452	
453				// --- Section 3: Active Health Cooldowns ---
454				fmt.Fprintln(out)
455				fmt.Fprintf(out, "Active Health Cooldowns\n")
456				fmt.Fprintf(out, "%s\n", strings.Repeat("-", 70))
457				if len(activeCooldowns) == 0 {
458					fmt.Fprintln(out, "  (none)")
459				} else {
460					fmt.Fprintf(out, "%-20s %-12s %-24s %s\n",
461						"ROUTE", "PROVIDER", "FAILED_AT", "COOLDOWN_UNTIL")
462					for _, c := range activeCooldowns {
463						failedAtStr := "-"
464						if !c.failedAt.IsZero() {
465							failedAtStr = c.failedAt.UTC().Format("2006-01-02T15:04:05Z")
466						}
467						fmt.Fprintf(out, "%-20s %-12s %-24s %s\n",
468							truncateRouteStr(c.route, 20),
469							c.provider,
470							failedAtStr,
471							c.cooldownUntil.UTC().Format("2006-01-02T15:04:05Z"),
472						)
473					}
474				}
475	
476				return nil
477			},
478		}
479		cmd.Flags().String("model", "", "Requested model route key (e.g. qwen3.5-27b)")
480		cmd.Flags().Bool("json", false, "Output JSON")
481		return cmd
482	}
