13	// Public event-type strings emitted by agentlib.DdxAgent.Execute, mirrored
14	// from CONTRACT-003 §"Event JSON shapes". Kept as constants here so the
15	// drain loop does not have to import the agent's internal/harnesses
16	// package (which is module-private).
17	const (
18		serviceEventRoutingDecision = "routing_decision"
19		serviceEventTextDelta       = "text_delta"
20		serviceEventToolCall        = "tool_call"
21		serviceEventToolResult      = "tool_result"
22		serviceEventStall           = "stall"
23		serviceEventFinal           = "final"
24		serviceEventCompaction      = "compaction"
25		serviceEventCompactionEnd   = "compaction.end"
