63	// runAgentViaService is the new RunAgent dispatch path that drives the
64	// agent through agentlib.DdxAgent.Execute and drains the resulting event
65	// channel into a DDx Result. Old in-package code paths (RunAgent legacy
66	// loop, embeddedCompactionConfig, buildAgentProvider, findTool,
67	// wrapProviderWithDeadlines, stall + compaction-stuck circuit breakers)
68	// stay in place; this function does NOT call them.
69	//
70	// Stall detection: we delegate to the agent's StallPolicy. The agent
71	// emits a stall event then a final event with Status="stalled".
72	func runAgentViaService(r *Runner, opts RunArgs) (*Result, error) {
73		promptText, err := r.resolvePrompt(opts)
74		if err != nil {
75			return nil, err
76		}
77	
78		model := r.resolveModel(opts, "agent")
79		timeout := r.resolveTimeout(opts)
80		wallClock := r.resolveWallClock(opts)
81	
82		wd := opts.WorkDir
83		if wd == "" {
84			wd, _ = os.Getwd()
85		}
86	
87		// Construct the service. Reuses NewServiceFromWorkDir so provider/model
88		// routing data lands on the agent the same way every other DDx command
89		// constructs it (see serviceconfig.go).
90		svc, err := NewServiceFromWorkDir(wd)
91		if err != nil {
92			return nil, fmt.Errorf("agent: build service: %w", err)
93		}
94	
95		// Resolve where to write the per-request session log.
96		logDir := opts.SessionLogDir
97		if logDir == "" {
98			logDir = r.Config.SessionLogDir
99		}
100		if logDir == "" {
101			logDir = DefaultLogDir
102		}
103	
104		providerTimeout := ResolveProviderRequestTimeout(wd, opts.Provider, model, 0)
105	
106		// Build the public ExecuteRequest per CONTRACT-003.
107		req := agentlib.ServiceExecuteRequest{
108			Prompt:          promptText,
109			Model:           model,
110			Provider:        opts.Provider,
111			Harness:         "agent",
112			ModelRef:        opts.ModelRef,
113			Reasoning:       agentlib.Reasoning(opts.Effort),
114			Permissions:     opts.Permissions,
115			WorkDir:         wd,
116			Timeout:         wallClock,
117			IdleTimeout:     timeout,
118			ProviderTimeout: providerTimeout,
119			SessionLogDir:   logDir,
120			Metadata:        opts.Correlation,
121		}
122	
123		parentCtx := opts.Context
124		if parentCtx == nil {
125			parentCtx = context.Background()
126		}
127		ctx, cancel := context.WithCancel(parentCtx)
128		defer cancel()
129	
130		start := time.Now()
131		events, err := svc.Execute(ctx, req)
132		if err != nil {
133			return nil, fmt.Errorf("agent: execute: %w", err)
134		}
135	
136		final, toolCalls, routing, actualPower := drainServiceEvents(events)
137		elapsed := time.Since(start)
138	
139		result := &Result{
140			Harness:    "agent",
141			Model:      model,
142			DurationMS: int(elapsed.Milliseconds()),
143			ToolCalls:  toolCalls,
144		}
145		if routing != nil {
146			result.Provider = routing.Provider
147			if routing.Model != "" {
148				result.Model = routing.Model
149			}
150		}
151		if actualPower > 0 {
152			result.ActualPower = actualPower
153		}
154		if final != nil {
155			// Normalized final text from the upstream harness (agent-32e8ff5e).
156			result.Output = final.FinalText
157			if final.Usage != nil {
158				// v0.9.1: Usage fields became *int so the API can distinguish
159				// "harness reported zero" from "harness didn't report". Treat
160				// nil as zero for DDx's int-valued result struct.
161				if final.Usage.InputTokens != nil {
162					result.InputTokens = *final.Usage.InputTokens
163				}
164				if final.Usage.OutputTokens != nil {
165					result.OutputTokens = *final.Usage.OutputTokens
166				}
167				if final.Usage.TotalTokens != nil {
168					result.Tokens = *final.Usage.TotalTokens
169				}
170			}
171			if final.CostUSD > 0 {
172				result.CostUSD = final.CostUSD
173			}
174			if final.RoutingActual != nil {
175				if result.Provider == "" {
176					result.Provider = final.RoutingActual.Provider
177				}
178				if final.RoutingActual.Model != "" {
179					result.Model = final.RoutingActual.Model
180				}
181			}
182			switch final.Status {
183			case "success", "":
184				// happy path; no-op
185			case "stalled":
186				result.ExitCode = 1
187				if final.Error != "" {
188					result.Error = "stalled: " + final.Error
189				} else {
190					result.Error = "stalled"
191				}
192			case "timed_out":
193				result.ExitCode = 1
194				result.Error = fmt.Sprintf("timeout after %v", wallClock.Round(time.Second))
195			case "cancelled":
196				result.ExitCode = 1
197				result.Error = "cancelled"
198			default:
199				result.ExitCode = 1
200				if final.Error != "" {
201					result.Error = final.Error
202				} else {
203					result.Error = final.Status
204				}
205			}
206			result.Error = appendProviderTimeoutHint(result.Error, providerTimeout)
207			if final.SessionLogPath != "" {
208				// surface as session ID for downstream cross-reference (mirrors
209				// the legacy path's AgentSessionID population).
210				result.AgentSessionID = final.SessionLogPath
211			}
212		}
213	
214		promptSource := opts.PromptSource
215		if promptSource == "" {
216			if opts.PromptFile != "" {
217				promptSource = opts.PromptFile
218			} else {
219				promptSource = "inline"
220			}
221		}
222		r.logSession(result, len(promptText), promptText, promptSource, opts.Correlation)
223		r.recordRoutingOutcome(result, elapsed, opts)
224		return result, nil
225	}
