13	const modelsProbeTimeout = 3 * time.Second
14	
15	func (f *CommandFactory) newAgentModelsCommand() *cobra.Command {
16		cmd := &cobra.Command{
17			Use:   "models",
18			Short: "List models for a configured provider",
19			Args:  cobra.NoArgs,
20			RunE: func(cmd *cobra.Command, args []string) error {
21				svc, err := agent.NewServiceFromWorkDir(f.WorkingDir)
22				if err != nil {
23					return fmt.Errorf("loading agent config: %w", err)
24				}
25	
26				ctx, cancel := context.WithTimeout(context.Background(), modelsProbeTimeout*2)
27				defer cancel()
28	
29				showAll, _ := cmd.Flags().GetBool("all")
30				providerName, _ := cmd.Flags().GetString("provider")
31	
32				providers, err := svc.ListProviders(ctx)
33				if err != nil {
34					return fmt.Errorf("listing providers: %w", err)
35				}
36	
37				// Build a provider-type lookup for the anthropic special case.
38				providerType := make(map[string]string, len(providers))
39				providerDefault := make(map[string]string, len(providers))
40				for _, p := range providers {
41					providerType[p.Name] = p.Type
42					providerDefault[p.Name] = p.DefaultModel
43				}
44	
45				if showAll {
46					for _, p := range providers {
47						fmt.Fprintf(cmd.OutOrStdout(), "[%s]\n", p.Name)
48						models, _ := svc.ListModels(ctx, agentlib.ModelFilter{Provider: p.Name})
49						printModels(cmd, p.Name, p.Type, p.DefaultModel, models)
50						fmt.Fprintln(cmd.OutOrStdout())
51					}
52					return nil
53				}
54	
55				name := providerName
56				if name == "" {
57					// Find the default provider.
58					for _, p := range providers {
59						if p.IsDefault {
60							name = p.Name
61							break
62						}
63					}
64				}
65				if name == "" && len(providers) > 0 {
66					name = providers[0].Name
67				}
68	
69				pType, ok := providerType[name]
70				if !ok {
71					return fmt.Errorf("unknown provider %q", name)
72				}
73	
74				if pType == "anthropic" {
75					fmt.Fprintln(cmd.OutOrStdout(), "Anthropic does not support model listing.")
76					if m := providerDefault[name]; m != "" {
77						fmt.Fprintf(cmd.OutOrStdout(), "Configured model: %s\n", m)
78					}
79					return nil
80				}
81	
82				models, err := svc.ListModels(ctx, agentlib.ModelFilter{Provider: name})
83				if err != nil {
84					return fmt.Errorf("listing models: %w", err)
85				}
86				printModels(cmd, name, pType, providerDefault[name], models)
87				return nil
88			},
89		}
90		cmd.Flags().String("provider", "", "Provider name (default: configured default)")
91		cmd.Flags().Bool("all", false, "List models for every configured provider")
92		return cmd
93	}
94	
95	// printModels renders the model list for one provider.
96	// The configured model is marked with "*". The auto-selected model (when no
97	// static model is set and rank 0 is available) is marked with ">".
98	// Catalog-recognized models show their catalog reference in brackets.
99	func printModels(cmd *cobra.Command, providerName, providerTyp, configuredModel string, models []agentlib.ModelInfo) {
100		out := cmd.OutOrStdout()
101	
102		if providerTyp == "anthropic" {
103			fmt.Fprintln(out, "  (anthropic — no model listing endpoint)")
104			return
105		}
106	
107		if len(models) == 0 {
108			fmt.Fprintln(out, "  (unavailable)")
109			return
110		}
111	
112		// Determine auto-selected model: first by rank when no model is configured.
113		autoSelected := ""
114		if configuredModel == "" {
115			// Find the model with the lowest RankPosition.
116			best := -1
117			for _, m := range models {
118				if best < 0 || m.RankPosition < best {
119					best = m.RankPosition
120					autoSelected = m.ID
121				}
122			}
123		}
124	
125		for _, m := range models {
126			marker := "  "
127			if m.ID == configuredModel {
128				marker = "* "
129			} else if m.ID == autoSelected {
130				marker = "> "
131			}
132			annotation := ""
133			if m.Power > 0 {
134				annotation = fmt.Sprintf("  [power: %d]", m.Power)
135			}
136			if m.CatalogRef != "" {
137				annotation += "  [catalog: " + m.CatalogRef + "]"
138			}
139			fmt.Fprintf(out, "%s%s%s\n", marker, m.ID, annotation)
140		}
141		if configuredModel == "" {
142			fmt.Fprintln(out)
143			fmt.Fprintln(out, "  * = configured  > = would auto-select")
144		}
145	}
