3	// CatalogEntry defines a logical model ref or profile's surface mappings.
4	// DDx uses this to project a ref (alias, profile, or canonical name) onto
5	// harness-specific surfaces and to surface deprecation/replacement metadata.
6	type CatalogEntry struct {
7		// Ref is the logical name (e.g. "qwen3", "cheap", "fast", "smart").
8		Ref string
9		// Surfaces maps a harness surface identifier to the concrete model string
10		// to pass to that harness. A ref absent from a surface's map means that
11		// surface cannot serve the ref.
12		Surfaces map[string]string
13		// Deprecated marks this ref as deprecated.
14		Deprecated bool
15		// ReplacedBy is the canonical replacement ref when Deprecated is true.
16		ReplacedBy string
17		// Blocked marks this ref as blocked; Resolve() returns ok=false for blocked entries.
18		Blocked bool
19	}
20	
21	// DeprecatedPin records a deprecated explicit model version string.
22	// Use this for exact concrete model pins (e.g. "claude-opus-4-5") that are
23	// stale — as opposed to logical alias deprecations in CatalogEntry.
24	type DeprecatedPin struct {
25		// Pin is the deprecated exact model string (e.g. "claude-opus-4-5").
26		Pin string
27		// ReplacedBy is the canonical replacement: a catalog ref (e.g. "smart")
28		// or a newer exact model string (e.g. "claude-opus-4-6").
29		ReplacedBy string
30		// Surface constrains the deprecation to a specific harness surface.
31		// Empty means the pin is deprecated across all surfaces.
32		Surface string
33	}
34	
35	// Catalog holds the shared DDx model catalog used for harness routing.
36	// It maps logical refs to harness-surface-specific concrete model strings.
37	// This is the authoritative source for aliases, profiles, canonical targets,
38	// and deprecation metadata across harness surfaces.
39	type Catalog struct {
40		entries         map[string]CatalogEntry
41		deprecatedPins  map[string]DeprecatedPin // keyed by Pin
42		blockedModelIDs map[string]bool          // concrete model IDs that routing must never select
43	}
44	
45	// catalog returns the catalog to use for runtime model metadata checks.
46	// Defaults to BuiltinCatalog.
47	func (r *Runner) catalog() *Catalog {
48		if r.Catalog != nil {
49			return r.Catalog
50		}
51		return BuiltinCatalog
52	}
53	
54	// NewCatalog creates a Catalog from a slice of entries.
55	func NewCatalog(entries []CatalogEntry) *Catalog {
56		c := &Catalog{entries: make(map[string]CatalogEntry, len(entries))}
57		for _, e := range entries {
58			c.entries[e.Ref] = e
59		}
60		return c
61	}
62	
63	// NewCatalogWithPins creates a Catalog from entries and deprecated pin records.
64	func NewCatalogWithPins(entries []CatalogEntry, pins []DeprecatedPin) *Catalog {
65		c := NewCatalog(entries)
66		c.deprecatedPins = make(map[string]DeprecatedPin, len(pins))
67		for _, p := range pins {
68			c.deprecatedPins[p.Pin] = p
69		}
70		return c
71	}
72	
73	// Clone returns an independent copy of the catalog.
74	func (c *Catalog) Clone() *Catalog {
75		if c == nil {
76			return NewCatalog(nil)
77		}
78		clone := &Catalog{
79			entries:         make(map[string]CatalogEntry, len(c.entries)),
80			deprecatedPins:  make(map[string]DeprecatedPin, len(c.deprecatedPins)),
81			blockedModelIDs: make(map[string]bool, len(c.blockedModelIDs)),
82		}
83		for ref, entry := range c.entries {
84			surfaces := make(map[string]string, len(entry.Surfaces))
85			for surface, model := range entry.Surfaces {
86				surfaces[surface] = model
87			}
88			entry.Surfaces = surfaces
89			clone.entries[ref] = entry
90		}
91		for pin, entry := range c.deprecatedPins {
92			clone.deprecatedPins[pin] = entry
93		}
94		for id, blocked := range c.blockedModelIDs {
95			clone.blockedModelIDs[id] = blocked
96		}
97		return clone
98	}
99	
100	// AddOrReplace inserts or replaces a catalog entry by Ref.
101	func (c *Catalog) AddOrReplace(entry CatalogEntry) {
102		if c.entries == nil {
103			c.entries = make(map[string]CatalogEntry)
104		}
105		c.entries[entry.Ref] = entry
106	}
107	
108	// AddBlockedModelID marks a concrete model ID as blocked.
109	// Resolve() returns ok=false for any model that resolves to a blocked ID.
110	func (c *Catalog) AddBlockedModelID(id string) {
111		if c.blockedModelIDs == nil {
112			c.blockedModelIDs = make(map[string]bool)
113		}
114		c.blockedModelIDs[id] = true
115	}
116	
117	// IsBlockedModelID reports whether a concrete model ID is blocked.
118	func (c *Catalog) IsBlockedModelID(id string) bool {
119		return c.blockedModelIDs[id]
120	}
121	
122	// CheckDeprecatedPin returns the DeprecatedPin entry for an explicit model
123	// string, or ok=false if the pin is not deprecated.
124	// If surface is non-empty and the pin entry has a Surface set, the match is
125	// narrowed to that surface only.
126	func (c *Catalog) CheckDeprecatedPin(pin, surface string) (DeprecatedPin, bool) {
127		if c.deprecatedPins == nil {
128			return DeprecatedPin{}, false
129		}
130		dp, ok := c.deprecatedPins[pin]
131		if !ok {
132			return DeprecatedPin{}, false
133		}
134		if dp.Surface != "" && surface != "" && dp.Surface != surface {
135			return DeprecatedPin{}, false
136		}
137		return dp, true
138	}
139	
140	// Resolve returns the concrete model string for a ref on the given surface.
141	// Returns ("", false) if the ref is unknown, not mapped to this surface,
142	// the entry is blocked, or the resolved concrete model is blocked.
143	func (c *Catalog) Resolve(ref, surface string) (string, bool) {
144		e, ok := c.entries[ref]
145		if !ok {
146			return "", false
147		}
148		if e.Blocked {
149			return "", false
150		}
151		model, ok := e.Surfaces[surface]
152		if !ok {
153			return "", false
154		}
155		if c.blockedModelIDs[model] {
156			return "", false
157		}
158		return model, true
159	}
160	
161	// Entry returns the full catalog entry for a ref.
162	func (c *Catalog) Entry(ref string) (CatalogEntry, bool) {
163		e, ok := c.entries[ref]
164		return e, ok
165	}
166	
167	// KnownOnAnySurface returns true if the ref has a mapping on at least one surface.
168	func (c *Catalog) KnownOnAnySurface(ref string) bool {
169		e, ok := c.entries[ref]
170		if !ok {
171			return false
172		}
173		return len(e.Surfaces) > 0
174	}
175	
176	// NormalizeModelRef resolves a raw --model input:
177	//   - If the value is known in the catalog on at least one surface, it is
178	//     treated as a logical ModelRef.
179	//   - Otherwise it is treated as an exact ModelPin (bypasses catalog).
180	//
181	// Exactly one of modelRef or modelPin will be non-empty.
182	func (c *Catalog) NormalizeModelRef(model string) (modelRef, modelPin string) {
183		if model == "" {
184			return "", ""
185		}
186		if c.KnownOnAnySurface(model) {
187			return model, ""
188		}
189		return "", model
190	}
191	
192	// BuiltinCatalog is the DDx shared routing catalog built from the YAML seed.
193	// Tier→surface→model assignments come from DefaultModelCatalogYAML so the data
194	// lives in one place. Policy aliases (qwen3, codex-mini) and deprecated pins
195	// are added here as they are routing policy decisions, not model metadata.
196	var BuiltinCatalog = buildBuiltinCatalog()
197	
198	func buildBuiltinCatalog() *Catalog {
199		yml := DefaultModelCatalogYAML()
200	
201		// Build tier entries from YAML seed.
202		var entries []CatalogEntry
203		for tierName, tierDef := range yml.Tiers {
204			entry := CatalogEntry{
205				Ref:      tierName,
206				Surfaces: make(map[string]string, len(tierDef.Surfaces)),
207			}
208			for surface, model := range tierDef.Surfaces {
209				entry.Surfaces[surface] = model
210			}
211			entries = append(entries, entry)
212		}
213	
214		// Policy aliases: logical names not tied to a tier profile.
215		entries = append(entries,
216			// qwen3 is only available via the embedded OpenAI-compatible surface.
217			CatalogEntry{
218				Ref:      "qwen3",
219				Surfaces: map[string]string{"embedded-openai": "qwen/qwen3-coder-next"},
220			},
221			// codex-mini is a deprecated alias for the cheap codex model.
222			CatalogEntry{
223				Ref:        "codex-mini",
224				Surfaces:   map[string]string{"codex": "gpt-5.4-mini"},
225				Deprecated: true,
226				ReplacedBy: "cheap",
227			},
228		)
229	
230		pins := []DeprecatedPin{
231			// Stale exact version strings for the claude (Anthropic) family.
232			{Pin: "claude-opus-4-5", Surface: "claude", ReplacedBy: "claude-opus-4-6"},
233			{Pin: "claude-3-5-sonnet-20241022", Surface: "claude", ReplacedBy: "claude-sonnet-4-6"},
234			{Pin: "claude-3-opus-20240229", Surface: "claude", ReplacedBy: "claude-opus-4-6"},
235			{Pin: "claude-3-sonnet-20240229", Surface: "claude", ReplacedBy: "claude-sonnet-4-6"},
236			// Stale exact version strings for the codex (OpenAI) family.
237			{Pin: "gpt-4o", Surface: "codex", ReplacedBy: "gpt-5.4-mini"},
238			{Pin: "gpt-4-turbo", Surface: "codex", ReplacedBy: "gpt-5.4"},
239			{Pin: "o1-2024-12-17", Surface: "codex", ReplacedBy: "gpt-5.4"},
240		}
241	
242		return NewCatalogWithPins(entries, pins)
243	}
