10	func statusError(status, source string, capturedAt time.Time) *StatusError {
11		return statusErrorDetail(status, "", source, capturedAt)
12	}
13	
14	func statusErrorDetail(status, detail, source string, capturedAt time.Time) *StatusError {
15		if status == "" || status == "connected" || status == "ok" {
16			return nil
17		}
18		if detail == "" {
19			detail = status
20		}
21		return &StatusError{
22			Type:      statusErrorType(status),
23			Detail:    detail,
24			Source:    source,
25			Timestamp: capturedAt,
26		}
27	}
28	
29	func statusErrorType(status string) string {
30		lower := strings.ToLower(status)
31		switch {
32		case strings.Contains(lower, "api_key") || strings.Contains(lower, "unauth") || strings.Contains(lower, "401") || strings.Contains(lower, "403"):
33			return "unauthenticated"
34		case lower == "unreachable" || strings.Contains(lower, "not found") || strings.Contains(lower, "connection") || strings.Contains(lower, "timeout"):
35			return "unavailable"
36		default:
37			return "error"
38		}
39	}
