41	func quotaStatus(fresh bool, windows []harnesses.QuotaWindow) string {
42		if len(windows) == 0 {
43			return "unknown"
44		}
45		if !fresh {
46			return "stale"
47		}
48		for _, w := range windows {
49			if w.State == "blocked" {
50				return "blocked"
51			}
52		}
53		return "ok"
54	}
