71	func providerAuthStatus(entry ServiceProviderEntry, status string, capturedAt time.Time) AccountStatus {
72		auth := AccountStatus{
73			Source:     "service provider config",
74			CapturedAt: capturedAt,
75			Fresh:      true,
76		}
77		if statusErrorType(status) == "unauthenticated" {
78			auth.Unauthenticated = true
79			auth.Detail = status
80			return auth
81		}
82		if entry.APIKey != "" {
83			auth.Authenticated = true
84			return auth
85		}
86		switch normalizeServiceProviderType(entry.Type) {
87		case "anthropic", "openrouter":
88			auth.Unauthenticated = true
89			auth.Detail = "api_key not configured"
90		default:
91			auth.Detail = "authentication not required or not reported"
92		}
