96	func providerEndpointStatus(entry ServiceProviderEntry, status string, modelCount int, capturedAt time.Time) []EndpointStatus {
97		source := strings.TrimRight(entry.BaseURL, "/") + "/models"
98		if entry.BaseURL == "" {
99			source = "service provider config"
100		}
101		base := EndpointStatus{
102			Name:       "default",
103			BaseURL:    entry.BaseURL,
104			ProbeURL:   source,
105			Status:     endpointStatus(status),
106			Source:     source,
107			CapturedAt: capturedAt,
108			Fresh:      true,
109			ModelCount: modelCount,
110			LastError:  statusError(status, source, capturedAt),
111		}
112		if base.Status == "connected" {
113			base.LastSuccessAt = capturedAt
114		}
115		out := []EndpointStatus{base}
116		for _, endpoint := range entry.Endpoints {
117			out = append(out, EndpointStatus{
118				Name:       endpoint.Name,
119				BaseURL:    endpoint.BaseURL,
120				ProbeURL:   strings.TrimRight(endpoint.BaseURL, "/") + "/models",
121				Status:     "unknown",
122				Source:     "service provider config",
123				CapturedAt: capturedAt,
124				Fresh:      false,
125			})
126		}
127		return out
128	}
