130	func providerQuotaState(entry ServiceProviderEntry, capturedAt time.Time) *QuotaState {
131		switch normalizeServiceProviderType(entry.Type) {
132		case "openrouter":
133			source := strings.TrimRight(entry.BaseURL, "/") + "/auth/key"
134			if entry.BaseURL == "" {
135				source = "openrouter /auth/key"
136			}
137			if entry.APIKey == "" {
138				return &QuotaState{
139					Source:     source,
140					Status:     "unauthenticated",
141					CapturedAt: capturedAt,
142					LastError: &StatusError{
143						Type:      "unauthenticated",
144						Detail:    "api_key not configured",
145						Source:    source,
146						Timestamp: capturedAt,
147					},
148				}
149			}
150			return &QuotaState{
151				Source:     source,
152				Status:     "unavailable",
153				CapturedAt: capturedAt,
154				LastError: &StatusError{
155					Type:      "unavailable",
156					Detail:    "quota probe not yet captured",
157					Source:    source,
158					Timestamp: capturedAt,
159				},
160			}
161		default:
162			return nil
163		}
164	}
165	
166	func endpointStatus(status string) string {
167		if status == "connected" {
168			return "connected"
169		}
170		if statusErrorType(status) == "unauthenticated" {
171			return "unauthenticated"
172		}
173		if status == "unreachable" || statusErrorType(status) == "unavailable" {
174			return "unreachable"
175		}
176		return "error"
177	}
