3	import (
4		"context"
5		"time"
6	)
7	
8	// RouteStatus returns global routing state across all configured routes.
9	// It is the operator dashboard view: cooldowns, recent decisions, and
10	// per-candidate health. Distinct from per-request ResolveRoute.
11	func (s *service) RouteStatus(ctx context.Context) (*RouteStatusReport, error) {
12		s.ensurePrimaryQuotaRefresh(ctx, quotaRefreshAsync)
13		sc := s.opts.ServiceConfig
14		report := &RouteStatusReport{
15			GeneratedAt: time.Now(),
16		}
17		// ADR-006 §5: populate routing-quality over a recent window
18		// (RouteStatusRoutingQualityWindow) regardless of whether a route
19		// catalog is configured — the metric reflects Execute traffic, not
20		// configured routes.
21		if s != nil && s.routingQuality != nil {
22			recent := s.routingQuality.snapshotRecent(RouteStatusRoutingQualityWindow, time.Time{})
23			report.RoutingQuality = computeRoutingQualityMetricsFromRecords(recent)
24		}
25		if sc == nil {
26			return report, nil
27		}
28	
29		cooldown := s.routeAttemptTTL()
30		activeAttempts := s.activeRouteAttempts(report.GeneratedAt, cooldown)
31	
32		routeNames := sc.ModelRouteNames()
33		report.Routes = make([]RouteStatusEntry, 0, len(routeNames))
34	
35		for _, routeName := range routeNames {
36			rc := sc.ModelRouteConfig(routeName)
37			entry := RouteStatusEntry{
38				Model:    routeName,
39				Strategy: rc.Strategy,
40			}
41	
42			// Populate LastDecision from cache.
43			if cached, ok := s.lookupRouteDecision(routeName); ok {
44				entry.LastDecision = cached.decision
45				entry.LastDecisionAt = cached.at
46			}
47	
48			// Build per-candidate status.
49			for _, cand := range rc.Candidates {
50				cs := RouteCandidateStatus{
51					Provider: cand.Provider,
52					Model:    cand.Model,
53					Priority: cand.Priority,
54				}
55				// Check cooldown state for this candidate.
56				cs.Cooldown = routeCandidateCooldown(sc, routeName, cand.Provider, cooldown)
57				if attemptCooldown := routeAttemptCandidateCooldown(activeAttempts, cand.Provider, cand.Model, cooldown); attemptCooldown != nil {
58					cs.Cooldown = attemptCooldown
59				}
60				cs.Healthy = cs.Cooldown == nil
61				// RecentLatencyMS and RecentSuccessRate: zero — observation store not yet wired.
62				entry.Candidates = append(entry.Candidates, cs)
63			}
64	
65			report.Routes = append(report.Routes, entry)
66		}
67	
68		return report, nil
69	}
70	
71	func routeAttemptCandidateCooldown(records []routeAttemptRecord, providerName, model string, cooldown time.Duration) *CooldownState {
72		var newest *routeAttemptRecord
73		for i := range records {
74			record := &records[i]
75			if record.key.Provider == "" {
76				continue
77			}
78			if providerName != "" && record.key.Provider != providerName {
79				continue
80			}
81			if record.key.Model != "" && model != "" && record.key.Model != model {
82				continue
83			}
84			if newest == nil || record.recordedAt.After(newest.recordedAt) {
85				newest = record
86			}
87		}
88		if newest == nil {
89			return nil
90		}
91		return routeAttemptCooldown(*newest, cooldown)
92	}
93	
94	// routeCandidateCooldown returns the active CooldownState for a specific
95	// (route, provider) pair, or nil if not in cooldown.
96	func routeCandidateCooldown(sc ServiceConfig, routeName, providerName string, cooldown time.Duration) *CooldownState {
97		workDir := sc.WorkDir()
98		if workDir == "" {
99			return nil
100		}
101		now := time.Now().UTC()
102		failures := serviceLoadRouteFailures(workDir, routeName)
103		failedAt, hasFail := failures[providerName]
104		if !hasFail {
105			return nil
106		}
107		until := failedAt.Add(cooldown)
108		if until.Before(now) {
109			return nil
110		}
111		return &CooldownState{
112			Reason:      "consecutive_failures",
113			Until:       until,
114			FailCount:   1,
115			LastAttempt: failedAt,
116		}
117	}
118	
119	// cacheRouteDecision stores a ResolveRoute result keyed by routeKey.
120	// Called by ResolveRoute after a successful resolution.
121	func (s *service) cacheRouteDecision(routeKey string, dec *RouteDecision) {
122		if routeKey == "" || dec == nil {
123			return
124		}
125		s.lastDecisionMu.Lock()
126		defer s.lastDecisionMu.Unlock()
127		if s.lastDecisionCache == nil {
128			s.lastDecisionCache = make(map[string]lastDecisionEntry)
129		}
130		s.lastDecisionCache[routeKey] = lastDecisionEntry{
131			decision: dec,
132			at:       time.Now(),
133		}
134	}
135	
136	// lookupRouteDecision retrieves a cached decision for routeKey.
137	func (s *service) lookupRouteDecision(routeKey string) (lastDecisionEntry, bool) {
138		s.lastDecisionMu.RLock()
139		defer s.lastDecisionMu.RUnlock()
140		if s.lastDecisionCache == nil {
141			return lastDecisionEntry{}, false
142		}
143		e, ok := s.lastDecisionCache[routeKey]
144		return e, ok
145	}
