63	// WriteModelCatalogYAML writes the catalog to the given path, creating parent dirs.
64	func WriteModelCatalogYAML(path string, cat *ModelCatalogYAML) error {
65		if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
66			return err
67		}
68		data, err := yaml.Marshal(cat)
69		if err != nil {
70			return err
71		}
72		return os.WriteFile(path, data, 0o644)
73	}
