75	// ApplyModelCatalogYAML overlays the YAML catalog onto a Catalog, adding or
76	// replacing entries for each tier defined in the YAML.
77	func ApplyModelCatalogYAML(cat *Catalog, yml *ModelCatalogYAML) {
78		if yml == nil || cat == nil {
79			return
80		}
81		for tierName, tierDef := range yml.Tiers {
82			entry := CatalogEntry{
83				Ref:      tierName,
84				Surfaces: make(map[string]string, len(tierDef.Surfaces)),
85			}
86			for surface, model := range tierDef.Surfaces {
87				entry.Surfaces[surface] = model
88			}
89			cat.AddOrReplace(entry)
90		}
91		for _, m := range yml.Models {
92			if m.Blocked {
93				cat.AddBlockedModelID(m.ID)
94			}
95		}
96	}
