382	// ValidateForExecuteLoopViaService is the production replacement for
383	// Runner.ValidateForExecuteLoop. When harness is empty it is a no-op (routing
384	// will pick at claim time). When harness is specified it confirms the harness
385	// exists in the service registry and (when model is set) attempts a
386	// ResolveRoute pre-flight.
387	func ValidateForExecuteLoopViaService(ctx context.Context, workDir, harnessName, model, provider, modelRef string) error {
388		if harnessName == "" {
389			return nil
390		}
391		if ctx == nil {
392			ctx = context.Background()
393		}
394		svc, err := NewServiceFromWorkDir(workDir)
395		if err != nil {
396			return fmt.Errorf("agent: build service: %w", err)
397		}
398		infos, err := svc.ListHarnesses(ctx)
399		if err != nil {
400			return fmt.Errorf("agent: list harnesses: %w", err)
401		}
402		found := false
403		for _, info := range infos {
404			if info.Name == harnessName {
405				found = true
406				if !info.Available {
407					return fmt.Errorf("agent: harness %s not available", harnessName)
408				}
409				break
410			}
411		}
412		if !found {
413			return fmt.Errorf("agent: unknown harness: %s", harnessName)
414		}
415	
416		// Pre-flight orphan-model check via ResolveRoute. Only meaningful when a
417		// model is provided and provider/model-ref are not set.
418		if model != "" && provider == "" && modelRef == "" && harnessName == "agent" {
419			if _, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{
420				Model:    model,
421				Harness:  harnessName,
422				ModelRef: modelRef,
423				Provider: provider,
424			}); err != nil {
425				return fmt.Errorf("agent: model %q is not routable: %w", model, err)
426			}
427		}
428		return nil
429	}
